#!/usr/bin/env python3
"""
patch_v330_rubber_band_snapback.py  (AGENTS.md §2.2 — function-anchored patcher)

WHAT: replaces enhanced_scanner._check_rubber_band (a %-from-EMA9 STATE check with
      a fake "double bar break" reasoning line the code never enforced) with a real
      SMB SNAPBACK detector: >= {1.25}% extension from the SESSION OPEN + a 1-min
      double-bar-break trigger within +1..+4 bars of the extreme + accel(1.3x) +
      RVOL>=1.5 + 2-fires/day-per-side cap. Long AND short.
WHY : 14d native-1min trade-replays validated +EV both sides — v329 long +0.27R/76%,
      v330 short +0.59R/74%, robust across ext buckets; edge concentrated in +1..+4
      bars (the +0 same-bar reversal is excluded). 1-min bars come from
      ib_historical_data (the IB-only training source) via
      self.technical_service._get_intraday_bars_from_db(sym,"1 min",60).

DRIFT NOTE: the sandbox enhanced_scanner.py differs from the DGX file (line-shifted),
      so this patcher is FUNCTION-ANCHORED: it asserts the live whole-file SHA equals
      the DGX baseline AND the exact _check_rubber_band bytes are present (count==1),
      replaces them, asserts the new function SHA, then py_compiles the whole file
      before writing. (A precomputed whole-file POST_SHA isn't possible without
      transferring the 452KB file; the compile + function-SHA guards + backup cover it.)

§2.2: PRE whole-file SHA guard + function PRE/POST SHA + anchor-uniqueness + compile
      guard + auto-backup + --check/--apply/--rollback.

Usage (repo root, DGX):
  .venv/bin/python /tmp/patch_v330_rubber_band_snapback.py --check
  .venv/bin/python /tmp/patch_v330_rubber_band_snapback.py --apply
  .venv/bin/python /tmp/patch_v330_rubber_band_snapback.py --rollback
Then: pytest backend/tests/test_v330_rubber_band.py -q ; commit ; ./start_backend.sh --force
"""
import base64, hashlib, sys, shutil, os, py_compile, tempfile

FILE = "backend/services/enhanced_scanner.py"
DGX_WHOLE_PRE = "b631ebad524d6fc8151cd4d9f979b73c0b1997337557a680035d6a9742e1e3e3"
PRE_FUNC_SHA  = "1901bcfc43a17ed9acfe9ece167b0562499a9da9f85ef58a1ad19cfbd6380def"
POST_FUNC_SHA = "6721b9f860c8b19c6875b426fe8fe535f4ddff27bf9d42c9dad96af7869888fa"
OLD_B64 = ""
NEW_B64 = ""
BACKUP = FILE + ".bak_v330"


def _sha(s):
    return hashlib.sha256(s.encode("utf-8")).hexdigest()


def _read():
    if not os.path.exists(FILE):
        print(f"ERROR: {FILE} not found (run from repo root)"); sys.exit(2)
    return open(FILE, encoding="utf-8").read()


def _old():
    return base64.b64decode(OLD_B64).decode("utf-8")


def _new():
    return base64.b64decode(NEW_B64).decode("utf-8")


def _compiles(text):
    with tempfile.NamedTemporaryFile("w", suffix=".py", delete=False) as tf:
        tf.write(text); tmp = tf.name
    try:
        py_compile.compile(tmp, doraise=True); return True
    except py_compile.PyCompileError as e:
        print("POST-PATCH COMPILE FAILED:\n", e); return False
    finally:
        os.unlink(tmp)


def check():
    src = _read(); cur = _sha(src); old = _old()
    print(f"file            : {FILE}")
    print(f"whole-file SHA  : {cur}")
    print(f"expected (DGX)  : {DGX_WHOLE_PRE}  {'OK' if cur == DGX_WHOLE_PRE else 'DRIFT!'}")
    print(f"func anchor     : present={old in src} count={src.count(old)}")
    print(f"func PRE sha    : {_sha(old)}  {'OK' if _sha(old) == PRE_FUNC_SHA else 'MISMATCH'}")
    if _new() in src:
        print("state           : ALREADY PATCHED")
    if cur != DGX_WHOLE_PRE:
        print("\nDRIFT: live file != DGX baseline. Re-extract the function and rebuild.")
        print("Upload: curl --data-binary @%s https://paste.rs/  (or just the function)" % FILE)
        return False
    if src.count(old) != 1:
        print("\nAnchor missing/ambiguous — abort."); return False
    print("\nREADY: --apply will install the SMB snapback rubber_band detector (long+short).")
    return True


def apply():
    src = _read(); old, new = _old(), _new()
    if new in src:
        print("Already patched. No-op."); return
    if _sha(src) != DGX_WHOLE_PRE:
        print(f"ABORT: whole-file SHA {_sha(src)} != DGX baseline. See --check."); sys.exit(3)
    if src.count(old) != 1:
        print(f"ABORT: anchor count={src.count(old)} (need 1)."); sys.exit(3)
    if _sha(old) != PRE_FUNC_SHA:
        print("ABORT: function PRE sha mismatch."); sys.exit(3)
    if _sha(new) != POST_FUNC_SHA:
        print("ABORT: embedded NEW function sha mismatch (corrupt patcher)."); sys.exit(3)
    patched = src.replace(old, new, 1)
    if not _compiles(patched):
        print("ABORT: patched file does not compile. No write."); sys.exit(3)
    shutil.copy2(FILE, BACKUP)
    with open(FILE, "w", encoding="utf-8") as f:
        f.write(patched)
    print(f"APPLIED. backup -> {BACKUP}")
    print(f"new whole-file SHA : {_sha(patched)}  (record this)")
    print("Verify: pytest backend/tests/test_v330_rubber_band.py -q")
    print("Then commit BEFORE restart, then ./start_backend.sh --force")


def rollback():
    src = _read(); old, new = _old(), _new()
    if old in src and _sha(src) == DGX_WHOLE_PRE:
        print("Already at baseline (unpatched). No-op."); return
    if new in src and src.count(new) == 1:
        restored = src.replace(new, old, 1)
        shutil.copy2(FILE, FILE + ".bak_pre_rollback")
        with open(FILE, "w", encoding="utf-8") as f:
            f.write(restored)
        ok = _sha(restored) == DGX_WHOLE_PRE
        print(f"ROLLED BACK via reverse-anchor. whole-file SHA == DGX baseline: {ok}")
        return
    if os.path.exists(BACKUP):
        bsrc = open(BACKUP, encoding="utf-8").read()
        if _sha(bsrc) == DGX_WHOLE_PRE:
            shutil.copy2(BACKUP, FILE)
            print(f"ROLLED BACK from {BACKUP} (== DGX baseline)."); return
    print("ABORT: could not safely roll back."); sys.exit(4)


if __name__ == "__main__":
    arg = sys.argv[1] if len(sys.argv) > 1 else "--check"
    {"--check": check, "--apply": apply, "--rollback": rollback}.get(arg, lambda: print("usage: --check | --apply | --rollback"))()
